// We use a simple tile strategy: tile over the output spatial dimensions.
// Each tile processes a contiguous block of output pixels for all output channels and batch.
// The tile size is limited by UB memory. For convolution, we need to hold:
// - A slice of input (inChannels * tileInputH * tileInputW)
// - A slice of weight (inChannels * outChannels * kH * kW)
// - A slice of output (outChannels * tileOutH * tileOutW)
// Approximate UB budget: 192KB floats => 49152 floats. We allocate conservatively.
static constexpr uint32_t UB_BUDGET_FLOATS = 45000;
static constexpr uint32_t ALIGN_ELEMS = 256;

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvTransposed2dAsymmetricInputAsymmetricKernelCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    // x: [N, C_in, H_in, W_in]
    // w: [C_in, C_out, kH, kW] for groups=1
